import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'invoiveStatusPipe'
})
export class InvoiveStatusPipe implements PipeTransform {

  transform(value: number, ...args: any[]): string {

    if (value === 0)
      return "UnPaid";
    if (value === 1)
      return "Partially Paid";
    if (value === 2)
      return "Paid";
    if (value === 3)
      return "Over Due";

    return "Unkown";
  }

}
